+            }
+            Err(e) => Err(classify_rusqlite_error_as_op(e)),
+        }
+    } else {
+        match tx.execute(trimmed, []) {
+            Ok(affected) => {
+                if let Some(ExpectedResult::AffectedRows(n)) = expected {
+                    if affected != *n {
+                        return Err(OpError::Fatal(format!(
+                            "affected mismatch: expected {n}, got {affected} for `{trimmed}`"
+                        )));
+                    }
+                }
+                Ok(())
+            }
+            Err(e) => Err(classify_rusqlite_error_as_op(e)),
+        }
+    }
